INSERT INTO `testimonials` VALUES
(1,'Ahmad Rizki','A.R.','Jakarta','Alhamdulillah, setelah 3 sesi dengan Ustadz Ahmad, kecemasan saya yang sudah 2 tahun akhirnya bisa teratasi. Pendekatan Islamnya sangat menenangkan dan membuat saya merasa aman. Sangat merekomendasikan!',5,1,1,'2025-12-25 08:46:27'),
(2,'Ibu Nurhasanah','N.H.','Bandung','Anak saya yang susah makan akhirnya mau makan sayur setelah terapi dengan Dr. Siti. Prosesnya menyenangkan dan anak saya tidak merasa takut sama sekali. Terima kasih banyak!',5,2,1,'2025-12-25 08:46:27'),
(3,'Dewi Safitri','D.S.','Surabaya','Saya sangat bersyukur menemukan Ustadzah Fatimah. Sebagai wanita, saya merasa nyaman curhat tentang masalah rumah tangga saya. Beliau sangat sabar dan memberikan solusi yang bijak berdasarkan Al-Quran dan Sunnah.',5,3,1,'2025-12-25 08:46:27'),
(4,'Budi Santoso','B.S.','Yogyakarta','Trauma masa kecil yang saya pendam selama 20 tahun akhirnya bisa dilepaskan. Proses hipnoterapinya sangat profesional dan saya merasa lebih ringan sekarang. Jazakallahu khairan!',5,1,1,'2025-12-25 08:46:27'),
(5,'Rina Amalia','R.A.','Semarang','Anak saya yang kena bullying di sekolah sekarang jadi lebih percaya diri setelah terapi. Dr. Siti sangat memahami psikologi anak dan pendekatannya sangat tepat.',5,2,1,'2025-12-25 08:46:27'),
(6,'Hana Permata','H.P.','Malang','Konflik dengan suami yang sudah berlarut-larut akhirnya bisa diselesaikan dengan baik setelah konseling dengan Ustadzah Fatimah. Rumah tangga kami sekarang jauh lebih harmonis.',5,3,1,'2025-12-25 08:46:27');
